import type {
  CanvasNodeConnectionEvent,
  CanvasNodeConnectionSide,
  CanvasNodeInteractionState,
  CanvasNodeVisualStatusTone,
} from "@workspace/ui/components/canvas-node/canvas-node";
import type { ReactNode } from "react";

export type DatabaseEngineKey =
  | "mongodb"
  | "mysql"
  | "postgresql"
  | "redis"
  | (string & {});

export type DatabaseNodeMetricKey = "cpu" | "memory" | "storage";

export type DatabaseNodeMetricValue = number | string;

export type DatabaseNodeStatusTone =
  | "available"
  | "binding"
  | "bound"
  | "complete"
  | "creating"
  | "degraded"
  | "deleting"
  | "error"
  | "failed"
  | "inaccessible"
  | "not-configured"
  | "pending"
  | "progressing"
  | "ready"
  | "reconciling"
  | "running"
  | "shutdown"
  | "stopped"
  | "stopping"
  | "succeeded"
  | "suspended"
  | "unconfigured"
  | "unhealthy"
  | "unknown"
  | (string & {});

export interface DatabaseNodeStatus {
  label: string;
  tone?: DatabaseNodeStatusTone;
  visualTone?: CanvasNodeVisualStatusTone;
}

export interface DatabaseNodeStates {
  displayEngine: string;
  engineKey?: DatabaseEngineKey;
  formattedVersion?: string;
  metrics?: Partial<Record<DatabaseNodeMetricKey, DatabaseNodeMetricValue>>;
  name: string;
  status?: DatabaseNodeStatus;
}

interface DatabaseNodeConnectionBase {
  displayValue?: string;
  id?: string;
  label: string;
  value?: string;
}

export interface DatabaseNodePrivateConnection
  extends DatabaseNodeConnectionBase {
  kind: "private";
  unavailableMessage?: string;
}

export interface DatabaseNodePublicConnection
  extends DatabaseNodeConnectionBase {
  kind: "public";
  provisioningMessage?: string;
  publicAccess: {
    enabled: boolean;
    loading?: boolean;
  };
}

export type DatabaseNodeConnection =
  | DatabaseNodePrivateConnection
  | DatabaseNodePublicConnection;

export type DatabaseNodeConnectionKey = string;

export type DatabaseNodeCopyConnectionHandler = (
  connection: DatabaseNodeConnection,
  index: number
) => Promise<void> | void;

export type DatabaseNodeTogglePublicConnectionHandler = (
  connection: DatabaseNodePublicConnection,
  index: number,
  nextEnabled: boolean
) => Promise<void> | void;

export type DatabaseNodeStartConnectionHandler = (
  side: CanvasNodeConnectionSide,
  event: CanvasNodeConnectionEvent
) => void;

export type DatabaseNodeQuickActionKey = "console" | "logs" | "metrics";

export type DatabaseNodeLifecycleActionKey =
  | "delete"
  | "restart"
  | "start"
  | "stop";

export interface DatabaseNodeAction {
  disabled?: boolean;
  loading?: boolean;
  onClick?: () => Promise<void> | void;
}

export type DatabaseNodeQuickActions = Partial<
  Record<DatabaseNodeQuickActionKey, DatabaseNodeAction>
>;

export type DatabaseNodeLifecycleActions = Partial<
  Record<DatabaseNodeLifecycleActionKey, DatabaseNodeAction>
>;

export interface DatabaseNodeActions {
  copyConnection?: DatabaseNodeCopyConnectionHandler;
  lifecycleActions?: DatabaseNodeLifecycleActions;
  quickActions?: DatabaseNodeQuickActions;
  togglePublicConnection?: DatabaseNodeTogglePublicConnectionHandler;
}

export interface DatabaseNodeMeta {
  copiedFeedbackMs?: number;
}

export interface DatabaseNodeState {
  connections?: DatabaseNodeConnection[];
  copiedConnectionKey?: DatabaseNodeConnectionKey | null;
  states: DatabaseNodeStates;
}

export interface DatabaseNodeContextValue {
  actions: DatabaseNodeActions;
  meta: DatabaseNodeMeta;
  state: DatabaseNodeState;
}

export interface DatabaseNodeProviderProps {
  children?: ReactNode;
  value: DatabaseNodeContextValue;
}

export interface DatabaseNodeRootProps {
  children?: ReactNode;
  connections?: DatabaseNodeConnection[];
  copiedConnectionKey?: DatabaseNodeConnectionKey | null;
  copiedFeedbackMs?: number;
  defaultExpanded?: boolean;
  expanded?: boolean;
  interaction?: CanvasNodeInteractionState;
  lifecycleActions?: DatabaseNodeLifecycleActions;
  onCopyConnection?: DatabaseNodeCopyConnectionHandler;
  onExpandedChange?: (expanded: boolean) => void;
  onStartConnection?: DatabaseNodeStartConnectionHandler;
  onTogglePublicConnection?: DatabaseNodeTogglePublicConnectionHandler;
  quickActions?: DatabaseNodeQuickActions;
  states: DatabaseNodeStates;
}

"use client";

import { createContext, use } from "react";

import type { DatabaseNodeContextValue } from "./database-node.types";

export const DatabaseNodeContext =
  createContext<DatabaseNodeContextValue | null>(null);

export function useDatabaseNode(): DatabaseNodeContextValue {
  const value = use(DatabaseNodeContext);

  if (!value) {
    throw new Error(
      "DatabaseNode: compound components must be used within DatabaseNode.Root"
    );
  }

  return value;
}

"use client";

import { DatabaseNodeContext } from "./database-node.context";
import type { DatabaseNodeProviderProps } from "./database-node.types";

export function DatabaseNodeProvider({
  children,
  value,
}: DatabaseNodeProviderProps) {
  return <DatabaseNodeContext value={value}>{children}</DatabaseNodeContext>;
}

"use client";

import {
  CANVAS_NODE_DEFAULT_COPIED_FEEDBACK_MS,
  CanvasNodeCopyFeedbackScope,
} from "@workspace/ui/components/canvas-node/canvas-node.copyable-row";
import { CanvasNodeRoot } from "@workspace/ui/components/canvas-node/canvas-node.root";

import { DatabaseNodeProvider } from "./database-node.provider";
import type {
  DatabaseNodeConnection,
  DatabaseNodeConnectionKey,
  DatabaseNodeContextValue,
  DatabaseNodeRootProps,
} from "./database-node.types";

export function getDatabaseNodeConnectionKey(
  connection: DatabaseNodeConnection,
  index: number
) {
  return connection.id ?? String(index);
}

export function canCopyDatabaseNodeConnection(
  connection: DatabaseNodeConnection
) {
  if (!connection.value) {
    return false;
  }

  if (connection.kind === "public" && !connection.publicAccess.enabled) {
    return false;
  }

  return true;
}

export function DatabaseNodeRoot({
  children,
  connections,
  copiedConnectionKey,
  copiedFeedbackMs = CANVAS_NODE_DEFAULT_COPIED_FEEDBACK_MS,
  defaultExpanded,
  expanded,
  interaction,
  lifecycleActions,
  onCopyConnection,
  onExpandedChange,
  onStartConnection,
  onTogglePublicConnection,
  quickActions,
  states,
}: DatabaseNodeRootProps) {
  return (
    <CanvasNodeRoot
      defaultExpanded={defaultExpanded}
      expanded={expanded}
      interaction={interaction}
      onExpandedChange={onExpandedChange}
      onStartConnection={onStartConnection}
    >
      <CanvasNodeCopyFeedbackScope
        copiedFeedbackMs={copiedFeedbackMs}
        copiedKey={copiedConnectionKey}
      >
        {({ copiedKey }) => {
          const value: DatabaseNodeContextValue = {
            actions: {
              copyConnection: onCopyConnection,
              lifecycleActions,
              quickActions,
              togglePublicConnection: onTogglePublicConnection,
            },
            meta: {
              copiedFeedbackMs,
            },
            state: {
              connections,
              copiedConnectionKey:
                copiedKey as DatabaseNodeConnectionKey | null,
              states,
            },
          };

          return (
            <DatabaseNodeProvider value={value}>
              {children}
            </DatabaseNodeProvider>
          );
        }}
      </CanvasNodeCopyFeedbackScope>
    </CanvasNodeRoot>
  );
}

import { Database } from "lucide-react";
import type { ComponentType } from "react";
import {
  type DbIconProps,
  MongoDbIcon,
  MySqlIcon,
  PostgreSqlIcon,
  RedisIcon as RedisAssetIcon,
} from "../../assets/db-icons";

import type { DatabaseEngineKey } from "./database-node.types";

export type DatabaseEngineIcon = ComponentType<DbIconProps>;

export function DatabaseFallbackIcon({ size = 24, ...props }: DbIconProps) {
  return <Database size={size} {...props} />;
}

export const PostgreSQLIcon = PostgreSqlIcon;
export const MySQLIcon = MySqlIcon;
export const RedisIcon = RedisAssetIcon;
export const MongoDBIcon = MongoDbIcon;

const DATABASE_ENGINE_ICONS = {
  mongodb: MongoDBIcon,
  mysql: MySQLIcon,
  postgresql: PostgreSQLIcon,
  redis: RedisIcon,
} as const satisfies Record<string, DatabaseEngineIcon>;

export function normalizeDatabaseEngineKey(engineKey: DatabaseEngineKey) {
  return engineKey.trim().toLowerCase();
}

export function getDatabaseEngineIcon(
  engineKey: DatabaseEngineKey | undefined
) {
  if (!engineKey) {
    return DatabaseFallbackIcon;
  }

  return (
    DATABASE_ENGINE_ICONS[
      normalizeDatabaseEngineKey(
        engineKey
      ) as keyof typeof DATABASE_ENGINE_ICONS
    ] ?? DatabaseFallbackIcon
  );
}

import type {
  CanvasNodeStatus,
  CanvasNodeVisualStatusTone,
} from "@workspace/ui/components/canvas-node/canvas-node";

import type { DatabaseNodeStatus } from "./database-node.types";

const POSITIVE_STATUSES = new Set([
  "accessible",
  "available",
  "bound",
  "complete",
  "ready",
  "running",
  "succeeded",
]);

const PROGRESS_STATUSES = new Set([
  "binding",
  "creating",
  "pending",
  "progressing",
  "reconciling",
]);

const WARNING_STATUSES = new Set(["degraded", "deleting", "stopping"]);

const NEGATIVE_STATUSES = new Set([
  "error",
  "failed",
  "inaccessible",
  "unhealthy",
]);

const NEUTRAL_STATUSES = new Set([
  "not-configured",
  "shutdown",
  "stopped",
  "suspended",
  "unconfigured",
  "unknown",
]);

function normalizeDatabaseStatusTone(input: string | undefined) {
  return input
    ?.trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-");
}

export function resolveDatabaseNodeVisualTone(
  status: DatabaseNodeStatus | undefined
): CanvasNodeVisualStatusTone {
  if (status?.visualTone) {
    return status.visualTone;
  }

  const tone = normalizeDatabaseStatusTone(status?.tone ?? status?.label);

  if (tone && POSITIVE_STATUSES.has(tone)) {
    return "positive";
  }

  if (tone && PROGRESS_STATUSES.has(tone)) {
    return "progress";
  }

  if (tone && WARNING_STATUSES.has(tone)) {
    return "warning";
  }

  if (tone && NEGATIVE_STATUSES.has(tone)) {
    return "negative";
  }

  if (tone && NEUTRAL_STATUSES.has(tone)) {
    return "neutral";
  }

  return "neutral";
}

export function resolveDatabaseNodeStatus(
  status: DatabaseNodeStatus | undefined
): CanvasNodeStatus {
  return {
    label: status?.label?.trim() || "Unknown",
    visualTone: resolveDatabaseNodeVisualTone(status),
  };
}

const CONNECTION_PROTOCOL_REGEX = /^([a-z][a-z0-9+.-]*:\/\/)(.*)$/i;

function maskSecretPart(value: string, preserveLeading: boolean) {
  if (!value) {
    return "";
  }

  if (!preserveLeading) {
    return "*******";
  }

  return `${value.slice(0, 1)}*******`;
}

function maskAuthorityCredentials(authority: string) {
  const atIndex = authority.lastIndexOf("@");

  if (atIndex <= 0) {
    return authority;
  }

  const credentials = authority.slice(0, atIndex);
  const destination = authority.slice(atIndex + 1);
  const colonIndex = credentials.indexOf(":");

  if (colonIndex === -1) {
    return `${maskSecretPart(credentials, true)}@${destination}`;
  }

  const username = credentials.slice(0, colonIndex);
  const password = credentials.slice(colonIndex + 1);

  return `${maskSecretPart(username, true)}:${maskSecretPart(
    password,
    false
  )}@${destination}`;
}

export function maskDatabaseConnectionString(value: string) {
  if (!value) {
    return value;
  }

  const protocolMatch = value.match(CONNECTION_PROTOCOL_REGEX);

  if (!protocolMatch) {
    return maskAuthorityCredentials(value);
  }

  const protocol = protocolMatch[1] ?? "";
  const authority = protocolMatch[2] ?? "";

  return `${protocol}${maskAuthorityCredentials(authority)}`;
}

"use client";

import { CanvasNode } from "@workspace/ui/components/canvas-node/canvas-node";
import { Switch } from "@workspace/ui/components/switch";
import { cn } from "@workspace/ui/lib/utils";
import {
  Activity,
  Cpu,
  FileText,
  HardDrive,
  MemoryStick,
  Pause,
  Play,
  RotateCcw,
  SquareTerminal,
  Trash2,
} from "lucide-react";
import type { ComponentType, SVGProps } from "react";

import { getDatabaseEngineIcon } from "./database-engine-icons";
import { useDatabaseNode } from "./database-node.context";
import { maskDatabaseConnectionString } from "./database-node.mask";
import {
  canCopyDatabaseNodeConnection,
  getDatabaseNodeConnectionKey,
} from "./database-node.root";
import { resolveDatabaseNodeStatus } from "./database-node.status";
import type {
  DatabaseNodeConnection,
  DatabaseNodeLifecycleActionKey,
  DatabaseNodeMetricKey,
  DatabaseNodePublicConnection,
  DatabaseNodeQuickActionKey,
} from "./database-node.types";

const METRIC_ITEMS = [
  { icon: Cpu, key: "cpu", label: "CPU" },
  { icon: MemoryStick, key: "memory", label: "Memory" },
  { icon: HardDrive, key: "storage", label: "Storage" },
] as const satisfies readonly {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: DatabaseNodeMetricKey;
  label: string;
}[];

const QUICK_ACTION_ITEMS = [
  { icon: Activity, key: "metrics", label: "Open metrics" },
  { icon: SquareTerminal, key: "console", label: "Open database console" },
  { icon: FileText, key: "logs", label: "Open logs" },
] as const satisfies readonly {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: DatabaseNodeQuickActionKey;
  label: string;
}[];

interface LifecycleActionItem {
  icon: ComponentType<SVGProps<SVGSVGElement>>;
  key: DatabaseNodeLifecycleActionKey;
  label: string;
  tone?: "destructive" | "info" | "muted" | "success";
}

const LIFECYCLE_ACTION_ITEMS: readonly LifecycleActionItem[] = [
  { icon: RotateCcw, key: "restart", label: "Restart", tone: "info" },
  { icon: Trash2, key: "delete", label: "Delete", tone: "destructive" },
  { icon: Pause, key: "stop", label: "Stop", tone: "muted" },
  { icon: Play, key: "start", label: "Start", tone: "success" },
] as const;

function formatDatabaseSubtitle({
  displayEngine,
  formattedVersion,
}: {
  displayEngine: string;
  formattedVersion?: string;
}) {
  return `Database ${displayEngine}${formattedVersion ? ` ${formattedVersion}` : ""}`;
}

function formatDatabaseMetricValue(value: number | string | undefined) {
  if (typeof value === "number") {
    return `${value}%`;
  }

  const trimmed = value?.trim();

  return trimmed || "--";
}

function getConnectionDisplayValue(connection: DatabaseNodeConnection) {
  if (connection.kind === "public" && !connection.publicAccess.enabled) {
    return null;
  }

  if (connection.value) {
    return (
      connection.displayValue ?? maskDatabaseConnectionString(connection.value)
    );
  }

  if (connection.kind === "public") {
    return connection.provisioningMessage ?? "Provisioning connection string";
  }

  return connection.unavailableMessage ?? "Connection unavailable";
}

export function DatabaseNodeContent() {
  return (
    <CanvasNode.Card surfaceClassName="database-node-surface">
      <CanvasNode.Header>
        <DatabaseNodeHeaderContent />
      </CanvasNode.Header>
      <CanvasNode.Body>
        <DatabaseNodeBodyContent />
      </CanvasNode.Body>
      <CanvasNode.Footer>
        <DatabaseNodeFooterContent />
      </CanvasNode.Footer>
    </CanvasNode.Card>
  );
}

export function DatabaseNodeHeaderContent({
  className,
}: {
  className?: string;
}) {
  const {
    state: { states },
  } = useDatabaseNode();
  const Icon = getDatabaseEngineIcon(states.engineKey);
  const subtitle = formatDatabaseSubtitle(states);

  return (
    <div className={cn("flex min-w-0 flex-1 items-center gap-1.5", className)}>
      <span className="flex min-w-0 flex-1 items-center gap-1.5">
        <span className="flex size-9 shrink-0 items-center justify-center rounded-lg bg-white/5">
          <Icon aria-hidden className="size-4" strokeWidth={2} />
        </span>
        <span className="flex min-w-0 flex-1 flex-col gap-1.5">
          <span
            className="min-w-0 truncate font-normal text-sm text-zinc-50 leading-5"
            title={states.name}
          >
            {states.name}
          </span>
          <span
            className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4"
            title={subtitle}
          >
            {subtitle}
          </span>
        </span>
      </span>
      <DatabaseNodeHeaderMenu />
    </div>
  );
}

export function DatabaseNodeBodyContent({ className }: { className?: string }) {
  return (
    <div className={cn("database-node-body-content pt-2.5", className)}>
      <DatabaseNodeConnectionList />
      <DatabaseNodeActionBar />
    </div>
  );
}

export function DatabaseNodeConnectionList({
  className,
}: {
  className?: string;
}) {
  const {
    state: { connections = [] },
  } = useDatabaseNode();
  const scrollable = connections.length > 2;

  if (connections.length === 0) {
    return (
      <div
        className={cn(
          "database-node-connection-empty flex min-w-0 items-center rounded-lg bg-zinc-950/20 px-2.5 text-muted-foreground text-xs leading-4",
          className
        )}
        data-slot="database-node-connection-empty"
      >
        No connections
      </div>
    );
  }

  return (
    <div
      className={cn(
        "database-node-connection-list flex min-w-0 flex-col gap-2",
        className
      )}
      data-scrollable={scrollable || undefined}
      data-slot="database-node-connection-list"
    >
      {connections.map((connection, index) => (
        <DatabaseNodeConnectionRow
          connection={connection}
          index={index}
          key={getDatabaseNodeConnectionKey(connection, index)}
        />
      ))}
    </div>
  );
}

export function DatabaseNodeConnectionRow({
  className,
  connection,
  index,
}: {
  className?: string;
  connection: DatabaseNodeConnection;
  index: number;
}) {
  const { actions } = useDatabaseNode();
  const copyable = canCopyDatabaseNodeConnection(connection);
  const displayValue = getConnectionDisplayValue(connection);
  const rowKey = getDatabaseNodeConnectionKey(connection, index);
  const publicSwitch =
    connection.kind === "public" ? (
      <CanvasNode.CopyableRowControl className="pointer-events-auto relative z-20 flex shrink-0 items-center">
        <DatabaseNodePublicSwitch connection={connection} index={index} />
      </CanvasNode.CopyableRowControl>
    ) : null;

  return (
    <CanvasNode.CopyableRow
      className={cn(
        "database-node-connection-row relative flex min-w-0 flex-col gap-2 rounded-lg bg-zinc-950/20 p-2.5 transition-colors",
        displayValue ? "min-h-18" : "min-h-11",
        !copyable && "database-node-connection-row-static",
        className
      )}
      copyAriaLabel={`Copy ${connection.label}`}
      copyable={copyable}
      copyValue={connection.value}
      data-slot="database-node-connection-row"
      onCopy={
        actions.copyConnection
          ? () => actions.copyConnection?.(connection, index)
          : undefined
      }
      rowKey={rowKey}
      title={connection.value}
    >
      {({ copied, copyable: rowCopyable }) => (
        <>
          <div
            className={cn(
              "relative z-10 flex min-w-0 items-center justify-between gap-2",
              rowCopyable ? "pointer-events-none" : "pointer-events-auto"
            )}
          >
            <span className="min-w-0 truncate font-normal text-muted-foreground text-xs leading-4">
              {connection.label}
            </span>
            {publicSwitch}
          </div>
          {displayValue ? (
            <div
              aria-hidden={rowCopyable ? true : undefined}
              className={cn(
                "relative z-10 flex h-7 min-w-0 items-center justify-between gap-2 py-1.5 text-left font-normal text-xs leading-4",
                rowCopyable
                  ? "pointer-events-none text-zinc-50"
                  : "text-muted-foreground"
              )}
              data-copied={copied ? "true" : undefined}
              data-slot="database-node-connection-value"
              title={connection.value ?? displayValue}
            >
              <span className="min-w-0 truncate">{displayValue}</span>
              <CanvasNode.CopyableRowIndicator />
            </div>
          ) : null}
        </>
      )}
    </CanvasNode.CopyableRow>
  );
}

function DatabaseNodePublicSwitch({
  connection,
  index,
}: {
  connection: DatabaseNodePublicConnection;
  index: number;
}) {
  const { actions } = useDatabaseNode();
  const disabled =
    connection.publicAccess.loading || !actions.togglePublicConnection;

  return (
    <Switch
      aria-label={
        connection.publicAccess.enabled
          ? "Disable public connection"
          : "Enable public connection"
      }
      checked={connection.publicAccess.enabled}
      className="database-node-public-switch pointer-events-auto relative z-20 cursor-pointer data-disabled:cursor-not-allowed data-disabled:opacity-70"
      disabled={disabled}
      onCheckedChange={(nextEnabled) => {
        if (!actions.togglePublicConnection) {
          return;
        }

        Promise.resolve(
          actions.togglePublicConnection(connection, index, nextEnabled)
        ).catch(() => undefined);
      }}
      size="lg"
      variant="brand"
    />
  );
}

export function DatabaseNodeActionBar({ className }: { className?: string }) {
  const {
    actions: { quickActions },
  } = useDatabaseNode();

  return (
    <CanvasNode.ActionBar className={className}>
      {QUICK_ACTION_ITEMS.map((item) => {
        const action = quickActions?.[item.key];
        const Icon = item.icon;

        return (
          <CanvasNode.ActionButton
            action={action}
            aria-label={item.label}
            key={item.key}
            title={item.label}
          >
            <Icon aria-hidden className="size-4" />
          </CanvasNode.ActionButton>
        );
      })}
    </CanvasNode.ActionBar>
  );
}

export function DatabaseNodeFooterContent({
  className,
}: {
  className?: string;
}) {
  const {
    state: {
      states: { metrics, status },
    },
  } = useDatabaseNode();
  const visualStatus = resolveDatabaseNodeStatus(status);

  return (
    <div
      className={cn(
        "database-node-footer-content flex w-full min-w-0 items-center justify-between gap-2 text-xs leading-none",
        className
      )}
      data-slot="database-node-footer-content"
    >
      <CanvasNode.FooterStatus status={visualStatus} />
      <CanvasNode.Metrics>
        {METRIC_ITEMS.map((item) => {
          const Icon = item.icon;

          return (
            <CanvasNode.Metric
              key={item.key}
              label={item.label}
              value={formatDatabaseMetricValue(metrics?.[item.key])}
            >
              <Icon aria-hidden className="size-3.5 shrink-0" />
            </CanvasNode.Metric>
          );
        })}
      </CanvasNode.Metrics>
    </div>
  );
}

function DatabaseNodeHeaderMenu() {
  const {
    actions: { lifecycleActions },
  } = useDatabaseNode();

  return (
    <CanvasNode.ActionMenu aria-label="Open database actions">
      {LIFECYCLE_ACTION_ITEMS.map((item) => {
        const action = lifecycleActions?.[item.key];
        const Icon = item.icon;

        return (
          <CanvasNode.ActionMenuItem
            action={action}
            actionKey={item.key}
            icon={<Icon aria-hidden className="size-4" />}
            key={item.key}
            tone={item.tone}
          >
            {item.label}
          </CanvasNode.ActionMenuItem>
        );
      })}
    </CanvasNode.ActionMenu>
  );
}

.database-node-connection-list {
  scrollbar-width: none;
}

.database-node-connection-list[data-scrollable] {
  max-height: calc((var(--spacing) * 18 * 2) + (var(--spacing) * 2));
  overflow-y: auto;
}

.database-node-connection-list::-webkit-scrollbar {
  display: none;
}

.database-node-connection-empty {
  min-height: calc(var(--spacing) * 11);
}

"use client";

import "./database-node.css";

import {
  DatabaseNodeActionBar,
  DatabaseNodeBodyContent,
  DatabaseNodeConnectionList,
  DatabaseNodeConnectionRow,
  DatabaseNodeContent,
  DatabaseNodeFooterContent,
  DatabaseNodeHeaderContent,
} from "./database-node.content";
import { DatabaseNodeRoot } from "./database-node.root";

// biome-ignore lint/performance/noBarrelFile: compound component public API includes colocated helpers.
export {
  DatabaseFallbackIcon,
  getDatabaseEngineIcon,
  MongoDBIcon,
  MySQLIcon,
  PostgreSQLIcon,
  RedisIcon,
} from "./database-engine-icons";
export { maskDatabaseConnectionString } from "./database-node.mask";
export {
  canCopyDatabaseNodeConnection,
  getDatabaseNodeConnectionKey,
} from "./database-node.root";
export {
  resolveDatabaseNodeStatus,
  resolveDatabaseNodeVisualTone,
} from "./database-node.status";
export type {
  DatabaseEngineKey,
  DatabaseNodeAction,
  DatabaseNodeActions,
  DatabaseNodeConnection,
  DatabaseNodeConnectionKey,
  DatabaseNodeContextValue,
  DatabaseNodeCopyConnectionHandler,
  DatabaseNodeLifecycleActionKey,
  DatabaseNodeLifecycleActions,
  DatabaseNodeMeta,
  DatabaseNodeMetricKey,
  DatabaseNodeMetricValue,
  DatabaseNodePrivateConnection,
  DatabaseNodeProviderProps,
  DatabaseNodePublicConnection,
  DatabaseNodeQuickActionKey,
  DatabaseNodeQuickActions,
  DatabaseNodeRootProps,
  DatabaseNodeStartConnectionHandler,
  DatabaseNodeState,
